263→  const containerRef = useRef<HTMLDivElement>(null);
264→  const viewRef = useRef<EditorView | null>(null);
265→  const onChangeRef = useRef(onChange);
266→  const onValidationChangeRef = useRef(onValidationChange);
267→  const isExternalUpdate = useRef(false);
268→
269→  const themeCompartment = useMemo(() => new Compartment(), []);
270→  const highlightCompartment = useMemo(() => new Compartment(), []);
271→
272→  onChangeRef.current = onChange;
273→  onValidationChangeRef.current = onValidationChange;
274→
275→  useImperativeHandle(ref, () => ({
276→    getValue: () => viewRef.current?.state.doc.toString() ?? '',
277→    setValue: (val: string) => {
278→      const view = viewRef.current;
279→      if (!view) return;
280→      isExternalUpdate.current = true;
281→      view.dispatch({
282→        changes: { from: 0, to: view.state.doc.length, insert: val },
283→      });
284→      isExternalUpdate.current = false;
285→    },
286→    getView: () => viewRef.current,
287→  }));
288→
289→  useEffect(() => {
290→    if (!containerRef.current) return;
291→
292→    const json5ParseLinter = linter(
293→      (view): Diagnostic[] => {
294→        const doc = view.state.doc.toString();
295→        if (!doc.trim()) return [];
296→        try {
297→          JSON5.parse(doc);
298→          onValidationChangeRef.current?.(false, null);
299→          return [];
300→        } catch (e) {
301→          const msg = (e as SyntaxError).message || 'Invalid JSON';
302→          const lineMatch = msg.match(/at (\d+):(\d+)/);
303→          let from = 0;
304→          let to = Math.min(doc.length, 1);
305→          if (lineMatch) {
306→            const line = parseInt(lineMatch[1], 10);
307→            const col = parseInt(lineMatch[2], 10);
308→            const lineInfo = view.state.doc.line(Math.min(line, view.state.doc.lines));
309→            from = lineInfo.from + Math.min(col - 1, lineInfo.length);
310→            to = Math.min(from + 1, lineInfo.to);
311→          }
312→          onValidationChangeRef.current?.(true, msg);
313→          return [{ from, to, severity: 'error', message: msg, source: 'json5' }];
314→        }
315→      },
316→      { delay: 300 },
317→    );
318→
319→    const schemaLinter = linter(sduiSchemaLinter, { delay: 500 });
320→
321→    const updateListener = EditorView.updateListener.of(update => {
322→      if (update.docChanged && !isExternalUpdate.current) {
323→        const doc = update.state.doc.toString();
324→        onChangeRef.current(doc);
325→      }
326→    });
327→
328→    const initialTheme = isDarkMode ? darkTheme : lightTheme;
329→    const initialHighlight = isDarkMode
330→      ? syntaxHighlighting(darkHighlightStyle)
331→      : syntaxHighlighting(defaultHighlightStyle, { fallback: true });
332→
333→    const state = EditorState.create({
334→      doc: value,
335→      extensions: [
336→        lineNumbers(),
337→        highlightActiveLineGutter(),
338→        highlightActiveLine(),
339→        drawSelection(),
340→        rectangularSelection(),
341→        bracketMatching(),
342→        foldGutter(),
343→        highlightSelectionMatches(),
344→        history(),
345→        javascript(),
346→        highlightCompartment.of(initialHighlight),
347→        lintGutter(),
348→        json5ParseLinter,
349→        schemaLinter,
350→        sduiAutocompletion(),
351→        themeCompartment.of(initialTheme),
352→        updateListener,
353→        keymap.of([
354→          ...completionKeymap,
355→          indentWithTab,
356→          ...defaultKeymap,
357→          ...historyKeymap,
358→          ...foldKeymap,
359→          ...searchKeymap,
360→        ]),
361→        EditorView.lineWrapping,
362→        EditorState.tabSize.of(2),
363→      ],
364→    });
365→
366→    const view = new EditorView({
367→      state,
368→      parent: containerRef.current,
369→    });
370→
371→    viewRef.current = view;
372→
373→    return () => {
374→      view.destroy();
375→      viewRef.current = null;
376→    };
377→  // eslint-disable-next-line react-hooks/exhaustive-deps
378→  }, []);
379→
380→  useEffect(() => {
381→    const view = viewRef.current;
382→    if (!view) return;
383→
384→    const newTheme = isDarkMode ? darkTheme : lightTheme;
385→    const newHighlight = isDarkMode
386→      ? syntaxHighlighting(darkHighlightStyle)
387→      : syntaxHighlighting(defaultHighlightStyle, { fallback: true });
388→
389→    view.dispatch({
390→      effects: [
391→        themeCompartment.reconfigure(newTheme),
392→        highlightCompartment.reconfigure(newHighlight),
393→      ],
394→    });
395→  }, [isDarkMode, themeCompartment, highlightCompartment]);
396→
397→  useEffect(() => {
398→    const view = viewRef.current;
399→    if (!view) return;
400→    const currentDoc = view.state.doc.toString();
401→    if (currentDoc !== value && value) {
402→      isExternalUpdate.current = true;
403→      view.dispatch({
404→        changes: { from: 0, to: view.state.doc.length, insert: value },
405→      });
406→      isExternalUpdate.current = false;
407→    }
408→  }, [value]);
409→
410→  return (
411→    <div
412→      ref={containerRef}
413→      style={{ height: '100%', overflow: 'hidden' }}
414→    />
415→  );
416→});
