      mb: spacingProp,
      contextKey: { type: 'string' },
    },
    required: ['label'],
  },
  button: {
    type: 'object',
    properties: {
      text: { type: 'string' },
      disabled: { type: 'boolean' },
      mt: spacingProp,
      mb: spacingProp,
      icon: { type: 'string' },
      isLoading: { type: 'boolean' },
      testID: { type: 'string' },
    },
    required: ['text'],
  },
  link: {
    type: 'object',
    properties: {
      text: { type: 'string' },
      color: { type: 'string' },
      mt: spacingProp,
      mb: spacingProp,
      align: { type: 'string' },
    },
    required: ['text'],
  },
  alert: {
    type: 'object',
    properties: {
      label: { type: 'string' },
      type: { type: 'string' },
