  1→import {
  2→  autocompletion,
  3→  type CompletionContext,
  4→  type CompletionResult,
  5→  type Completion,
  6→} from '@codemirror/autocomplete';
  7→import { knownTypes, componentPropsSchemas } from './sduiSchema';
  8→
  9→interface PropSchema {
 10→  type: string;
 11→  properties?: Record<string, PropDef>;
 12→  required?: readonly string[];
 13→  enum?: readonly string[];
 14→  nullable?: boolean;
 15→}
 16→
 17→interface PropDef {
 18→  type?: string;
 19→  enum?: readonly string[];
 20→  nullable?: boolean;
 21→  const?: string;
 22→  items?: object;
 23→}
 24→
 25→const spacingValues = [
 26→  'none', 'xxxs', 'xxs', 'xs', 'smaller', 'sm', 'md', 'lg', 'xl', 'xxl', 'xxxl',
 27→];
 28→
 29→const screenTopLevelKeys = ['id', 'context', 'header', 'body', 'footer'];
 30→
 31→const componentStructureKeys = ['type', 'props', 'visible'];
 32→
 33→function getTypeDescription(type: string): string {
 34→  const descriptions: Record<string, string> = {
 35→    heading: 'Large title text (headingMDL)',
 36→    text: 'Configurable text with type/color/bold',
 37→    section_heading: 'Section subtitle (subtitleXXL)',
 38→    balance_display: 'Points balance with label and values',
 39→    points_input: 'Numeric input field for points/reais',
 40→    button: 'CTA button with text and optional icon',
 41→    link: 'Pressable text link',
 42→    alert: 'Info/warning/error alert box',
 43→    list_text_icon: 'List of items with icon + description',
 44→    separator: 'Horizontal line divider',
 45→    icon_text_row: 'Row with icon and text side-by-side',
 46→    nav_header: 'Navigation header with back button',
 47→    rich_text: 'Inline formatted text with bold/link/icon nodes',
 48→  };
 49→  return descriptions[type] ?? type;
 50→}
 51→
 52→function getPropDetail(_propName: string, propDef: PropDef): string {
 53→  if (propDef.enum) return `enum: ${propDef.enum.join(' | ')}`;
 54→  if (propDef.type === 'boolean') return 'boolean';
 55→  if (propDef.type === 'number') return 'number';
 56→  if (propDef.type === 'string') return 'string';
 57→  if (propDef.type === 'array') return 'array';
 58→  if (propDef.type === 'object') return 'object';
 59→  return '';
 60→}
 61→
 62→function isInsideStringLiteral(doc: string, pos: number): boolean {
 63→  let inString = false;
 64→  let stringChar = '';
 65→
 66→  for (let i = 0; i < pos; i++) {
 67→    const ch = doc[i];
 68→    if (inString) {
 69→      if (ch === '\\') { i++; continue; }
 70→      if (ch === stringChar) inString = false;
 71→    } else if (ch === '"' || ch === "'") {
 72→      inString = true;
 73→      stringChar = ch;
 74→    }
 75→  }
 76→  return inString;
 77→}
 78→
 79→function sduiCompletionSource(context: CompletionContext): CompletionResult | null {
 80→  const doc = context.state.doc.toString();
 81→  const pos = context.pos;
 82→
 83→  if (!context.explicit) {
 84→    const charBefore = pos > 0 ? doc[pos - 1] : '';
 85→    if (charBefore && /[{}[\]:,\s]/.test(charBefore)) {
 86→      return null;
 87→    }
 88→  }
 89→
 90→  const beforeChar = doc.slice(Math.max(0, pos - 80), pos);
 91→
 92→  const typeValueMatch = beforeChar.match(/"type"\s*:\s*"([^"]*)$/);
 93→  if (typeValueMatch) {
 94→    const prefix = typeValueMatch[1];
 95→    const from = pos - prefix.length;
 96→    const options: Completion[] = (knownTypes as readonly string[]).map(t => ({
 97→      label: t,
 98→      type: 'enum',
 99→      detail: getTypeDescription(t),
100→      boost: t.startsWith(prefix) ? 2 : 0,
101→    }));
102→    return { from, options, filter: true };
103→  }
104→
105→  const spacingValueMatch = beforeChar.match(
106→    /"(?:mt|mb|ml|mr)"\s*:\s*"([^"]*)$/
107→  );
108→  if (spacingValueMatch) {
109→    const prefix = spacingValueMatch[1];
110→    const from = pos - prefix.length;
111→    const options: Completion[] = spacingValues.map(v => ({
112→      label: v,
113→      type: 'enum',
114→      detail: 'spacing token',
115→    }));
116→    return { from, options, filter: true };
117→  }
118→
119→  const propValueMatch = beforeChar.match(/"(\w+)"\s*:\s*"([^"]*)$/);
120→  if (propValueMatch) {
121→    const propName = propValueMatch[1];
122→    const prefix = propValueMatch[2];
123→    const from = pos - prefix.length;
124→
125→    if (['mt', 'mb', 'ml', 'mr'].includes(propName)) {
126→      return {
127→        from,
128→        options: spacingValues.map(v => ({
129→          label: v,
130→          type: 'enum' as const,
131→          detail: 'spacing token',
132→        })),
133→        filter: true,
134→      };
135→    }
136→
137→    if (propName === 'align') {
138→      return {
139→        from,
140→        options: ['left', 'center', 'right'].map(v => ({
141→          label: v,
142→          type: 'enum' as const,
143→          detail: 'text alignment',
144→        })),
145→        filter: true,
146→      };
147→    }
148→
149→    if (propName === 'keyboardType') {
150→      return {
151→        from,
152→        options: ['numeric', 'default', 'email-address', 'phone-pad'].map(v => ({
153→          label: v,
154→          type: 'enum' as const,
155→          detail: 'keyboard type',
156→        })),
157→        filter: true,
158→      };
159→    }
160→  }
161→
162→  if (isInsideStringLiteral(doc, pos)) return null;
163→
164→  if (isInsidePropsObject(doc, pos)) {
165→    const componentType = getComponentTypeForPropsAt(doc, pos);
166→    if (componentType) {
167→      const schema = componentPropsSchemas[componentType] as PropSchema | undefined;
168→      if (schema?.properties) {
169→        const word = context.matchBefore(/[\w"]+/);
170→        if (!word && !context.explicit) return null;
171→        const from = word?.from ?? pos;
172→        const existingKeys = getExistingKeysInObject(doc, pos);
173→        const required = (schema.required as readonly string[] | undefined) ?? [];
174→
175→        const options: Completion[] = Object.entries(schema.properties)
176→          .filter(([key]) => !existingKeys.has(key))
177→          .map(([key, def]) => {
178→            const isRequired = required.includes(key);
179→            const detail = getPropDetail(key, def as PropDef);
180→            return {
181→              label: `"${key}"`,
182→              displayLabel: key,
183→              type: isRequired ? 'property' : 'variable',
184→              detail: `${detail}${isRequired ? ' (required)' : ''}`,
185→              boost: isRequired ? 10 : 0,
186→              apply: buildPropApply(key, def as PropDef),
187→            };
188→          });
189→
190→        if (options.length === 0) return null;
191→        return { from, options, filter: true };
192→      }
193→    }
194→  }
195→
196→  if (isInsideComponentObject(doc, pos)) {
197→    const word = context.matchBefore(/[\w"]+/);
198→    if (!word && !context.explicit) return null;
199→    const from = word?.from ?? pos;
200→    const existingKeys = getExistingKeysInObject(doc, pos);
201→
202→    const options: Completion[] = componentStructureKeys
203→      .filter(key => !existingKeys.has(key))
204→      .map(key => {
205→        const detail = key === 'type' ? 'component type (required)'
206→          : key === 'props' ? 'component properties (required)'
207→          : 'conditional visibility';
208→        return {
209→          label: `"${key}"`,
210→          displayLabel: key,
211→          type: 'property',
212→          detail,
213→          boost: key === 'type' ? 10 : key === 'props' ? 9 : 0,
214→          apply: key === 'type' ? '"type": ""'
215→            : key === 'props' ? '"props": {}'
216→            : '"visible": { "rule": {} }',
217→        };
218→      });
219→
220→    if (options.length === 0) return null;
221→    return { from, options, filter: true };
222→  }
223→
224→  if (isInsideTopLevelObject(doc, pos)) {
225→    const word = context.matchBefore(/[\w"]+/);
226→    if (!word && !context.explicit) return null;
227→    const from = word?.from ?? pos;
228→    const existingKeys = getExistingKeysInObject(doc, pos);
229→
230→    const options: Completion[] = screenTopLevelKeys
231→      .filter(key => !existingKeys.has(key))
232→      .map(key => ({
233→        label: `"${key}"`,
234→        displayLabel: key,
235→        type: 'property',
236→        detail: key === 'id' ? 'screen identifier (required)'
237→          : key === 'body' ? 'component list (required)'
238→          : key === 'context' ? 'interpolation data'
239→          : key === 'header' ? 'screen header component'
240→          : 'screen footer component',
241→        boost: key === 'id' ? 10 : key === 'body' ? 9 : 0,
242→        apply: key === 'id' ? '"id": ""'
243→          : key === 'body' ? '"body": []'
244→          : key === 'context' ? '"context": {}'
245→          : key === 'header' ? '"header": { "type": "", "props": {} }'
246→          : '"footer": { "type": "", "props": {} }',
247→      }));
248→
249→    if (options.length === 0) return null;
250→    return { from, options, filter: true };
251→  }
252→
253→  return null;
254→}
255→
256→function buildPropApply(key: string, def: PropDef): string {
257→  if (def.type === 'boolean') return `"${key}": false`;
258→  if (def.type === 'number') return `"${key}": 0`;
259→  if (def.type === 'array') return `"${key}": []`;
260→  if (def.type === 'object') return `"${key}": {}`;
261→  return `"${key}": ""`;
262→}
263→
264→function isInsidePropsObject(doc: string, pos: number): boolean {
265→  const before = doc.slice(0, pos);
266→  let depth = 0;
267→  let inStr = false;
268→  let strCh = '';
269→
270→  for (let i = before.length - 1; i >= 0; i--) {
271→    const ch = before[i];
272→
273→    if (inStr) {
274→      if (ch === strCh && (i === 0 || before[i - 1] !== '\\')) inStr = false;
275→      continue;
276→    }
277→    if (ch === '"' || ch === "'") { inStr = true; strCh = ch; continue; }
278→
279→    if (ch === '}') depth++;
280→    if (ch === '{') {
281→      depth--;
282→      if (depth < 0) {
283→        const preceding = before.slice(Math.max(0, i - 30), i).trim();
284→        return /["']props["']\s*:\s*$/.test(preceding);
285→      }
286→    }
287→  }
288→  return false;
289→}
290→
291→function getComponentTypeForPropsAt(doc: string, pos: number): string | null {
292→  const before = doc.slice(0, pos);
293→  let depth = 0;
294→
295→  for (let i = before.length - 1; i >= 0; i--) {
296→    if (before[i] === '}') depth++;
297→    if (before[i] === '{') {
298→      depth--;
299→      if (depth < 0) {
300→        const outerStart = before.lastIndexOf('{', i - 1);
301→        if (outerStart >= 0) {
302→          const outerChunk = doc.slice(outerStart, outerStart + 300);
303→          const typeMatch = outerChunk.match(/"type"\s*:\s*"([^"]+)"/);
304→          if (typeMatch?.[1] && (knownTypes as readonly string[]).includes(typeMatch[1])) {
305→            return typeMatch[1];
306→          }
307→        }
308→        break;
309→      }
310→    }
311→  }
312→  return null;
313→}
314→
315→function isInsideComponentObject(doc: string, pos: number): boolean {
316→  const before = doc.slice(0, pos);
317→  let depth = 0;
318→
319→  for (let i = before.length - 1; i >= 0; i--) {
320→    if (before[i] === '}' || before[i] === ']') depth++;
321→    if (before[i] === '{' || before[i] === '[') {
322→      depth--;
323→      if (depth < 0) {
324→        if (before[i] === '[') {
325→          const preceding = before.slice(Math.max(0, i - 30), i).trim();
326→          return /["']body["']\s*:\s*$/.test(preceding);
327→        }
328→        const preceding = before.slice(Math.max(0, i - 30), i).trim();
329→        if (/,\s*$/.test(preceding) || /\[\s*$/.test(preceding)) {
330→          const bracketSearch = before.slice(0, i);
331→          const bracketPos = bracketSearch.lastIndexOf('[');
332→          if (bracketPos >= 0) {
333→            const beforeBracket = bracketSearch.slice(Math.max(0, bracketPos - 30), bracketPos).trim();
334→            return /["']body["']\s*:\s*$/.test(beforeBracket);
335→          }
336→        }
337→        return false;
338→      }
339→    }
340→  }
341→  return false;
342→}
343→
344→function isInsideTopLevelObject(doc: string, pos: number): boolean {
345→  const before = doc.slice(0, pos);
