import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { type SDUISnippet, getSnippetsByCategory, filterSnippets } from './sduiSnippets';

interface SnippetMenuProps {
  isDarkMode: boolean;
  onSelect: (snippet: SDUISnippet) => void;
  onClose: () => void;
}

export function SnippetMenu({ isDarkMode, onSelect, onClose }: SnippetMenuProps) {
  const [query, setQuery] = useState('');
  const [selectedIndex, setSelectedIndex] = useState(0);
  const inputRef = useRef<HTMLInputElement>(null);
  const listRef = useRef<HTMLDivElement>(null);

  const filtered = useMemo(() => filterSnippets(query), [query]);
  const grouped = useMemo(() => {
    if (!query.trim()) return getSnippetsByCategory();
    const items = filtered;
    if (items.length === 0) return [];
    return [{ category: 'results' as const, label: 'Results', items }];
  }, [query, filtered]);
  const flatItems = useMemo(() => grouped.flatMap(g => g.items), [grouped]);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  useEffect(() => {
    setSelectedIndex(0);
  }, [query]);

  useEffect(() => {
    const active = listRef.current?.querySelector('[data-active="true"]');
    active?.scrollIntoView({ block: 'nearest' });
  }, [selectedIndex]);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Escape') {
        e.preventDefault();
        onClose();
        return;
      }
      if (e.key === 'ArrowDown') {
        e.preventDefault();
        setSelectedIndex(i => Math.min(i + 1, flatItems.length - 1));
        return;
      }
      if (e.key === 'ArrowUp') {
        e.preventDefault();
        setSelectedIndex(i => Math.max(i - 1, 0));
        return;
      }
      if (e.key === 'Enter') {
        e.preventDefault();
        if (flatItems[selectedIndex]) onSelect(flatItems[selectedIndex]);
        return;
      }
    },
    [flatItems, selectedIndex, onSelect, onClose],
  );

  const s = isDarkMode ? darkStyles : lightStyles;

  return (
    <div style={s.backdrop} onClick={onClose}>
      <div style={s.container} onClick={e => e.stopPropagation()} onKeyDown={handleKeyDown}>
        <div style={s.searchRow}>
          <input
            ref={inputRef}
            style={s.input}
            type="text"
            placeholder="Find a snippet…"
            value={query}
            onChange={e => setQuery(e.target.value)}
          />
          <kbd style={s.kbd}>Esc</kbd>
        </div>
        <div ref={listRef} style={s.list}>
          {flatItems.length === 0 && (
            <div style={s.empty}>No snippets match "{query}"</div>
          )}
          {grouped.map(group => (
            <div key={group.category}>
              <div style={s.groupLabel}>{group.label}</div>
              {group.items.map(item => {
                const idx = flatItems.indexOf(item);
                const isActive = idx === selectedIndex;
                return (
                  <div
                    key={item.id}
                    data-active={isActive}
                    style={{
                      ...s.item,
                      ...(isActive ? s.itemActive : {}),
                    }}
                    onClick={() => onSelect(item)}
                    onMouseEnter={() => setSelectedIndex(idx)}
                  >
                    <span style={s.itemBadge}>{item.category === 'screen' ? 'Screen' : item.category === 'structure' ? 'Struct' : 'Comp'}</span>
                    <span style={s.itemLabel}>{item.label}</span>
                    <span style={s.itemDesc}>{item.description}</span>
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

